import{o as s,c as a,D as i}from"./framework.2deede19.js";const d='{"title":"Глава 11","description":"","frontmatter":{"title":"Глава 11","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-08-30T00:00:00.000Z"},"relativePath":"texts/malini-vijayottara/11.md","lastUpdated":1625430017494}',l={},n=i('<div class="stanza"><a href="#s8.1" id="s8.1" class="num">8.1</a><p>Теперь поведаю о дикше, самой труднодостижимой. Творящей наслаждение и Освобождение, творящей прямое видение .</p></div><div class="stanza"><a href="#s8.2" id="s8.2" class="num">8.2</a><p>Для нее не нужны никакие мандалы, жертвенные ямы и прочее. Перед ней не (выполняется) ньяса и прочее, а омовение - по желанию .</p></div><div class="stanza"><a href="#s8.3" id="s8.3" class="num">8.3</a><p>Войдя в место жертвоприношения, хорошо умащенное, почитаемое, обратившись лицом на восток или на север облаченный в прекрасные цветы .</p></div><div class="stanza"><a href="#s8.4" id="s8.4" class="num">8.4</a><p>Созерцая сияющую Шакти от стоп до головы, следует созерцать сгорающее тело посредством махамудры .</p></div><div class="stanza"><a href="#s8.5" id="s8.5" class="num">8.5</a><p>В порядке анулома следует созерцать малини, являющую амриту, ради нисхождения ее в тело. Эта дхьяна выполняется в уме .</p></div><div class="stanza"><a href="#s8.6" id="s8.6" class="num">8.6</a><p>Затем следует созерцать, как было описано ранее, очищение адхв в теле. Затем, очистив предметы, следует вести (Кундалини) Шакти к амрите .</p></div><div class="stanza"><a href="#s8.7" id="s8.7" class="num">8.7</a><p>Во всех обрядах знающий ритуал должен жертвовать Малини, пребывающей в середине высшей сферы, или всей высшей (сфере) целиком, о Возлюбленная!</p></div><div class="stanza"><a href="#s8.8" id="s8.8" class="num">8.8</a><p>В начале следует почитать Ганешу для устранения препятствий. Затем, приступив к (почитанию) своего гуру, следует почитать семью гуру .</p></div><div class="stanza"><a href="#s8.9" id="s8.9" class="num">8.9</a><p>После Ганеши следует почтить все множество мантр, их владыкам следует поднести аргхью .</p></div><div class="stanza"><a href="#s8.10" id="s8.10" class="num">8.10</a><p>По окончании следует почитать Видью. Эта Видья есть Махешвари. После (почитания) мантры, видьи и Ганеши следует наполниться кула Шакти .</p></div><div class="stanza"><a href="#s8.11" id="s8.11" class="num">8.11</a><p>На восточном, южном и северном направлении почитаются четыре Махешвари и прочие: находящиеся, начиная с востока и заканчивая северо-востоком, Индрани и прочие .</p></div><div class="stanza"><a href="#s8.12" id="s8.12" class="num">8.12</a><p>Выше следует почитать Бога в форме кута (КША), и Ану мантры, дживу в форме палки, дживу пребывающую в вверху трезубца .</p></div><div class="stanza"><a href="#s8.13" id="s8.13" class="num">8.13</a><p>Правый большой палец внизу, затем левая грудь, после него живот, горло, украшенные левым зубцом .</p></div><div class="stanza"><a href="#s8.14" id="s8.14" class="num">8.14</a><p>Затем Шива и язык, над ним - верхняя челюсть. Так образуется царь над йогини чакрами . (<em>Описывается мантра, к сожалению, не удалось расшифровать</em>)</p></div><div class="stanza"><a href="#s8.15" id="s8.15" class="num">8.15</a><p>Благодаря его произнесению является высшее сознание. Затем следует жертвовать, согласно правилу, восьмерке героев вместе с (их) Шакти .</p></div><div class="stanza"><a href="#s8.16" id="s8.16" class="num">8.16</a><p>Желая различных могуществ, следует представить вначале образ Шри, вплоть до стоп, вместе с гандхой, дхупой и прочим .</p></div><div class="stanza"><a href="#s8.17" id="s8.17" class="num">8.17</a><p>Затем, призвав ученика многократно и хорошо испытанного, окропив (при помощи) Рудра Шакти, следует поместить его перед божеством .</p></div><div class="stanza"><a href="#s8.18" id="s8.18" class="num">8.18</a><p>Оглядев свои ладони следует освятить их рудра Шакти. Затем следует поднести цветы с рук с благовониями по сторонам света .</p></div><div class="stanza"><a href="#s8.19" id="s8.19" class="num">8.19</a><p>Созерцая их безопорно, следует созерцать их как наполненные Шакти. Сжав их с шакти мантрой и нетрой, следует (поднести)их к глазам, как и ранее .</p></div><div class="stanza"><a href="#s8.20" id="s8.20" class="num">8.20</a><p>Следует поместить (в них) цветок. Это - Шакти пребывающая в руке. Куда упадет цветок, там будет обозначена Кула .</p></div><div class="stanza"><a href="#s8.21-22" id="s8.21-22" class="num">8.21-22</a><p>Затем его следует поднести к лицу и бросить к ногам (ученика). Затем у его головы почитая чакру (образованную) руками, знающий йогу пусть пропустит Шакти (через руки), пока она не войдет в голову (ученика). Это именуется правилом «руки Шивы», творящим прямое видение .</p></div><div class="stanza"><a href="#s8.23" id="s8.23" class="num">8.23</a><p>Затем следует поднести горшок, наполненный плодами миробала и т.д .. Сделав тело поддерживаемым Шакти, следует поставить перед собой ученика .</p></div><div class="stanza"><a href="#s8.24" id="s8.24" class="num">8.24</a><p>Одновременно с бросанием цветов правой рукой и произнесением мантры, следует взять горшок, пребывая умом в созерцании .</p></div><div class="stanza"><a href="#s8.25" id="s8.25" class="num">8.25</a><p>Посредством «руки Шивы», следует подняв поднести ее к лицу. С этим ритуалом подносится (сосуд), сделанный из дерева баньян .</p></div><div class="stanza"><a href="#s8.26" id="s8.26" class="num">8.26</a><p>Следует поднести зубочитску, о Деви, размером 16 ангул. Из всего приходящего произносящий мантру (гуру) не раздумывая должен выбрать (разновидность) шактипату;</p></div><div class="stanza"><a href="#s8.27" id="s8.27" class="num">8.27</a><p>Который подразделяется на медленный, умеренный и пр. Мудрый (должен выбрать разновидность): медленный, умеренный и др. Это именуется самая дикшей, производимой описанным выше утвердившимся (в ней) .</p></div><div class="stanza"><a href="#s8.28-29" id="s8.28-29" class="num">8.28-29</a><p>Когда желающий получить дикшу, жертвует (все) в уме, желая этого, как и раньше по порядку, йогин, почтив Владыку Кулы должен с нежность вглядеться и осмотреть ученика, созерцая усердно Шакти от стоп до головы;</p></div><div class="stanza"><a href="#s8.30-31" id="s8.30-31" class="num">8.30-31</a><p>Размещая очищаемые адхвы, созерцая проникновение во все адхвы, посредством описанной ранее шакти таттвы и прочего. Войдя в него, следует выполнить этот обряд. Посредством очищения корня, начинается очищение светом огня Шакти .</p></div><div class="stanza"><a href="#s8.32" id="s8.32" class="num">8.32</a><p>(Затем) следует соединить очищаемое с чистым, пребывая умом в созерцании. Так все (адхвы) очищаются, сжигаемые несравненным (огнем) .</p></div><div class="stanza"><a href="#s8.33" id="s8.33" class="num">8.33</a><p>Следует созерцать как они растворяются в Шиве, нишкале или в сакале. Посредством йоги соединяясь на пути со своим почитаемым источником .</p></div><div class="stanza"><a href="#s8.34" id="s8.34" class="num">8.34</a><p>Выполняется сжигание цветка, отделенного от своего источника. Благодаря этому, великомудрый, очищается мышление ученика .</p></div><div class="stanza"><a href="#s8.35" id="s8.35" class="num">8.35</a><p>Следует отметить признаки погружения (сознания) ананда и др посредством почитания. (Это) - ананда, удбхава, камйа, нидра и гхурни - пятая .</p></div><div class="stanza"><a href="#s8.36" id="s8.36" class="num">8.36</a><p>Наделенный (такими видами) шакти (паты) подразделяемыми на медленную, умеренную и т.д. он может сбросить оковы и принять оковы по своему желанию .</p></div><div class="stanza"><a href="#s8.37" id="s8.37" class="num">8.37</a><p>Приняв их, он может их разъединить для особого наслаждения. Ни для кого иного не является эта «одержимость» .</p></div><div class="stanza"><a href="#s8.38" id="s8.38" class="num">8.38</a><p>Посредством шакти он сможет сжечь их снаружи и внутри. Они сжигаются в нем, как дерево с отсеченными корнями .</p></div><p>Такова в священной «Малини виджайоттара тантре» одиннадцатая глава.</p>',36);l.render=function(i,d,l,p,c,v){return s(),a("div",null,[n])};export default l;export{d as __pageData};
